var CAPACITY = 3;
var bookings = $input.all().map(function(i){return i.json;}).filter(function(b){return !!b.date;});
var confirmedCount = {};
bookings.filter(function(b){
  return String(b.status||'').toLowerCase() === 'confirmed';
}).forEach(function(b){
  var id = b.slot_Id || b.slot_id || '';
  confirmedCount[id] = (confirmedCount[id]||0) + 1;
});
var pending = bookings.filter(function(b){
  var s = String(b.status||'').toLowerCase();
  return b.date && (s==='' || s==='pending');
});
var pendingCount = {};
pending.forEach(function(b){
  var id = b.slot_Id || b.slot_id || '';
  pendingCount[id] = (pendingCount[id]||0) + 1;
});
pending = pending.map(function(b){
  var id = b.slot_Id || b.slot_id || '';
  var conf = confirmedCount[id] || 0;
  var pend = pendingCount[id] || 0;
  var conflict = conf >= CAPACITY || (conf + pend) > CAPACITY;
  return Object.assign({}, b, {slot_status: conflict ? 'taken' : 'available'});
});
pending.sort(function(a,b){
  return String(a.date).localeCompare(String(b.date))||String(a.time).localeCompare(String(b.time));
});
return [{json:{bookings:pending,count:pending.length}}];

