var evtDates = settingsData.event_dates || 'June 24–26, 2026';
var evtVenue = settingsData.event_venue || 'Shanghai New International Expo Centre';
var vars = {'{{salesperson_name}}':d.salesperson_name||'','{{client_name}}':d.client_name||'','{{company}}':d.company||'','{{client_email}}':d.email||'','{{date}}':d.date||'','{{time}}':d.time||'','{{event_name}}':evtName,'{{event_dates}}':evtDates,'{{event_venue}}':evtVenue};
var subject = (tpl.subject||'').replace(/[\r\n]+/g,'').trim();
var body = (tpl.body||'').replace(/\\n/g,'\n');
Object.keys(vars).forEach(k=>{subject=subject.split(k).join(vars[k]);body=body.split(k).join(vars[k]);});
if(!/<[a-z]/i.test(body)){body='<div style="font-family:Arial,sans-serif;font-size:14px;color:#222;line-height:1.8">'+body.split('\n').join('<br>')+'</div>';}
return [{json:{to:d.salesperson_email,subject:subject,body:body}}];

var wb = $('Cancel Pending Webhook');
var body = wb.first().json.body || wb.first().json;
var slotId = String(body.slot_id || '');
var email = String(body.email || '');
var bookingId = String(body.booking_id || '');
var slots = $input.all().map(function(i){return i.json;});
var slot = slots.find(function(s){return String(s.Slot_Id||'')===slotId;});
var newCount = slot ? Math.max(0, parseInt(slot.booked_count||0)-1) : 0;
return [{json:{slot_Id:slotId,email:email,booking_id:bookingId,new_booked_count:String(newCount),new_slot_status:'available'}}];

var wb = $('Reschedule Webhook');
var body = wb.first().json.body || wb.first().json;
var oldSlotId = String(body.old_slot_id||'');
var newSlotId = String(body.new_slot_id||'');
var email = String(body.email||'');
var newDate = String(body.new_date||'');
var newTime = String(body.new_time||'');
var slots = $input.all().map(function(i){return i.json;});
var oldSlot = slots.find(function(s){return String(s.Slot_Id||'')===oldSlotId;});
var newSlot = slots.find(function(s){return String(s.Slot_Id||'')===newSlotId;});
var oldNewCount = oldSlot ? Math.max(0,parseInt(oldSlot.booked_count||0)-1) : 0;
var newBookCount = newSlot ? parseInt(newSlot.booked_count||0)+1 : 1;
var newCap = newSlot ? parseInt(newSlot.capacity||1) : 1;
var newSlotStatus = newBookCount >= newCap ? 'booked' : 'available';
return [{json:{old_slot_Id:oldSlotId,new_slot_Id:newSlotId,email:email,new_date:newDate,new_time:newTime,old_new_count:String(oldNewCount),new_count:String(newBookCount),new_slot_status:newSlotStatus}}];
